compliant:
private int count;

public int Count
{
    get { return count; }
    set { count = value; } // Compliant - uses 'value' keyword
}

private string name;

public string Name
{
    get => name;
    set => name = value; // Compliant - uses 'value' keyword
}

private event EventHandler myEvent;

public event EventHandler MyEvent
{
    add { myEvent += value; } // Compliant
    remove { myEvent -= value; } // Compliant
}
